  (** val target_from_states :
      coq_ResourceTable -> coq_InningsState -> overs -> coq_Interruption list
      -> coq_Interruption list -> int -> runs **)

  let target_from_states tbl t1 t2_allocated t1_ints t2_ints g50 =
    let r1 =
      effective_resources tbl (resources_at_start tbl t1.inn_overs_allocated)
        t1_ints
    in
    let r2 =
      effective_resources tbl (resources_at_start tbl t2_allocated) t2_ints
    in
    revised_target t1.inn_score r1 r2 g50

  (** val ball_revised_target :
      runs -> scaled_resource -> scaled_resource -> int -> runs **)

  let ball_revised_target t1_score r1 r2 g50 =
    if ltb r2 r1
    then add (div (mul t1_score r2) r1) (succ 0)
    else add
           (add t1_score
             (div (mul g50 (sub r2 r1))
               (of_num_uint (UIntDecimal (D1 (D0 (D0 (D0 (D0 Nil)))))))))
           (succ 0)

  (** val ball_par_score :
      runs -> scaled_resource -> scaled_resource -> int -> runs **)

  let ball_par_score t1_score r1 r2_used g50 =
    if ltb r2_used r1
    then div (mul t1_score r2_used) r1
    else add t1_score
           (div (mul g50 (sub r2_used r1))
             (of_num_uint (UIntDecimal (D1 (D0 (D0 (D0 (D0 Nil))))))))

  (** val ball_target_from_states :
      coq_BallResourceTable -> coq_DetailedInningsState -> balls ->
      coq_BallInterruption list -> coq_BallInterruption list -> int -> runs **)

  let ball_target_from_states tbl t1 t2_allocated_balls t1_ints t2_ints g50 =
    let r1 =
      effective_ball_resources tbl
        (ball_resources_at_start tbl t1.det_balls_allocated) t1_ints
    in
    let r2 =
      effective_ball_resources tbl
        (ball_resources_at_start tbl t2_allocated_balls) t2_ints
    in
    ball_revised_target t1.det_score r1 r2 g50

  (** val ball_resources_used_net :
      coq_BallResourceTable -> coq_DetailedInningsState ->
      coq_BallInterruption list -> scaled_resource **)

  let ball_resources_used_net tbl det ints =
    sub (ball_resources_used tbl det) (total_ball_resources_lost tbl ints)

  (** val ball_par_from_states :
      coq_BallResourceTable -> coq_DetailedInningsState ->
      coq_DetailedInningsState -> coq_BallInterruption list ->
      coq_BallInterruption list -> int -> runs **)

  let ball_par_from_states tbl t1 t2 t1_ints t2_ints g50 =
    let r1 =
      effective_ball_resources tbl
        (ball_resources_at_start tbl t1.det_balls_allocated) t1_ints
    in
    ball_par_score t1.det_score r1 (ball_resources_used_net tbl t2 t2_ints)
      g50

  type coq_MatchResult =
  | Team1Wins
  | Team2Wins
  | Tie
  | NoResult
  | Abandoned

  (** val determine_result :
      runs -> runs -> bool -> bool -> bool -> coq_MatchResult **)

  let determine_result target t2_score t2_completed t2_all_out min_overs_met0 =
    if leb target t2_score
    then Team2Wins
    else if t2_all_out
         then if eqb (add t2_score (succ 0)) target then Tie else Team1Wins
         else if negb min_overs_met0
              then NoResult
              else if negb t2_completed
                   then NoResult
                   else if eqb (add t2_score (succ 0)) target
                        then Tie
                        else Team1Wins

  (** val par_result : runs -> runs -> bool -> coq_MatchResult **)

  let par_result par t2_score min_overs_met0 =
    if negb min_overs_met0
    then NoResult
    else if ltb t2_score par
         then Team1Wins
         else if ltb par t2_score then Team2Wins else Tie

  type coq_MatchState = { match_format : coq_MatchFormat;
                          match_t1 : coq_InningsState;
                          match_t2 : coq_InningsState;
                          match_t1_interruptions : coq_Interruption list;
                          match_t2_interruptions : coq_Interruption list;
                          match_g50 : int }

  (** val match_format : coq_MatchState -> coq_MatchFormat **)

  let match_format m =
    m.match_format

  (** val match_t1 : coq_MatchState -> coq_InningsState **)

  let match_t1 m =
    m.match_t1

  (** val match_t2 : coq_MatchState -> coq_InningsState **)

  let match_t2 m =
    m.match_t2

  (** val match_t1_interruptions : coq_MatchState -> coq_Interruption list **)

  let match_t1_interruptions m =
    m.match_t1_interruptions

  (** val match_t2_interruptions : coq_MatchState -> coq_Interruption list **)

  let match_t2_interruptions m =
    m.match_t2_interruptions

  (** val match_g50 : coq_MatchState -> int **)

  let match_g50 m =
    m.match_g50

  (** val match_of_history :
      coq_MatchFormat -> coq_InningsState -> coq_InningsState ->
      coq_Interruption list -> int -> coq_MatchState **)

  let match_of_history fmt t1 t2 history g50 =
    { match_format = fmt; match_t1 = t1; match_t2 = t2;
      match_t1_interruptions = (interruptions_for (succ 0) history);
      match_t2_interruptions = (interruptions_for (succ (succ 0)) history);
      match_g50 = g50 }

  (** val compute_target : coq_ResourceTable -> coq_MatchState -> runs **)

  let compute_target tbl m =
    target_from_states tbl m.match_t1 m.match_t2.inn_overs_allocated
      m.match_t1_interruptions m.match_t2_interruptions m.match_g50

  (** val compute_par : coq_ResourceTable -> coq_MatchState -> runs **)

  let compute_par tbl m =
    let r1 =
      effective_resources tbl
        (resources_at_start tbl m.match_t1.inn_overs_allocated)
        m.match_t1_interruptions
    in
    let r2_used =
      sub (resources_used tbl m.match_t2)
        (total_resources_lost tbl m.match_t2_interruptions)
    in
    par_score m.match_t1.inn_score r1 r2_used m.match_g50

  (** val min_overs_met : coq_MatchState -> bool **)

  let min_overs_met m =
    leb m.match_format.min_overs_for_result m.match_t2.inn_overs_faced

  (** val compute_result :
      coq_ResourceTable -> coq_MatchState -> coq_MatchResult **)

  let compute_result tbl m =
    let target = compute_target tbl m in
    let t2 = m.match_t2 in
    determine_result target t2.inn_score (is_complete t2) (is_all_out t2)
      (min_overs_met m)

